#include <stdio.h>
#include <stdbool.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        bool seen[101] = {false};
        int cnt = 0;
        for (int i = 0; i < n; ++i) {
            int d;
            scanf("%d", &d);
            if (!seen[d]) {
                seen[d] = true;
                ++cnt;
            }
        }
        printf("%d\n", cnt);
    }
    return 0;
}

